from typing import List, Optional

class Solution:
    def mergeKLists(self, lists: List[Optional[object]]) -> Optional[object]:
        if not lists:
            return None
        interval = 1
        n = len(lists)
        while interval < n:
            for i in range(0, n - interval, interval * 2):
                lists[i] = self._merge_two(lists[i], lists[i + interval])
            interval *= 2
        return lists[0]

    def _merge_two(self, l1, l2):
        dummy = type('Node', (), {'val': 0, 'next': None})()
        curr = dummy
        while l1 and l2:
            if l1.val <= l2.val:
                curr.next, l1 = l1, l1.next
            else:
                curr.next, l2 = l2, l2.next
            curr = curr.next
        curr.next = l1 if l1 else l2
        return dummy.next
